const repos = $input.all().map(i => i.json.name);
const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
const results = { commits: [], pullRequests: [], issues: [] };

for (const repo of repos) {
  try {
    const commitsResp = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
      method: 'GET',
      url: `https://api.github.com/repos/psandis/${repo}/commits?since=${since}`,
      headers: { 'Accept': 'application/vnd.github.v3+json' },
      json: true
    });
    if (Array.isArray(commitsResp)) {
      for (const c of commitsResp) {
        results.commits.push({
          repo,
          sha: c.sha?.substring(0, 7),
          message: c.commit?.message,
          author: c.commit?.author?.name,
          date: c.commit?.author?.date,
          url: c.html_url
        });
      }
    }
  } catch (e) {}

  try {
    const prsResp = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
      method: 'GET',
      url: `https://api.github.com/repos/psandis/${repo}/pulls?state=all&sort=updated&direction=desc`,
      headers: { 'Accept': 'application/vnd.github.v3+json' },
      json: true
    });
    if (Array.isArray(prsResp)) {
      for (const pr of prsResp) {
        if (new Date(pr.updated_at) >= new Date(since)) {
          results.pullRequests.push({
            repo,
            number: pr.number,
            title: pr.title,
            state: pr.merged_at ? 'merged' : pr.state,
            author: pr.user?.login,
            url: pr.html_url
          });
        }
      }
    }
  } catch (e) {}

  try {
    const issuesResp = await this.helpers.httpRequestWithAuthentication.call(this, 'httpHeaderAuth', {
      method: 'GET',
      url: `https://api.github.com/repos/psandis/${repo}/issues?state=all&sort=updated&direction=desc&since=${since}`,
      headers: { 'Accept': 'application/vnd.github.v3+json' },
      json: true
    });
    if (Array.isArray(issuesResp)) {
      for (const issue of issuesResp) {
        if (!issue.pull_request) {
          results.issues.push({
            repo,
            number: issue.number,
            title: issue.title,
            state: issue.state,
            labels: issue.labels?.map(l => l.name) || [],
            url: issue.html_url
          });
        }
      }
    }
  } catch (e) {}
}

results.dateLabel = new Date().toISOString().split('T')[0];
results.generatedAt = new Date().toISOString();

return [{ json: results }];

