const response = $input.first().json;
const markdown = response.content[0].text;

const buffer = Buffer.from(markdown, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'digest.md', 'text/markdown');

return [{ json: { markdown }, binary: { data: binaryData } }];
